fn is_prime(n: i64) -> i64 = {
    if n < 2 { 0 }
    else if n == 2 { 1 }
    else if n % 2 == 0 { 0 }
    else {
        let mut i = 3;
        let limit = sqrt(n);
        while i <= limit {
            if n % i == 0 { return 0 }
            i = i + 2
        };
        1
    }
};

fn nth_prime(n: i64) -> i64 = {
    let mut count = 0;
    let mut candidate = 1;
    while count < n {
        candidate = candidate + 1;
        if is_prime(candidate) == 1 {
            count = count + 1
        }
    };
    candidate
};

fn main() -> i64 = {
    let t = read_int();
    let mut i = 0;
    while i < t {
        let n = read_int();
        let result = nth_prime(n);
        let _p = println(result);
        i = i + 1
    };
    0
};

